def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0 or item > capacity:
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.2:
            score = np.exp(-5 * ratio) * (1 - ratio)**2 + np.sin(3 * ratio * np.pi)
        elif 0.2 <= ratio < 0.5:
            score = np.log(ratio * 10 + 1) * 4 - np.cbrt(ratio)
        elif 0.5 <= ratio < 0.8:
            score = (1 / (1 + np.exp(-20 * (ratio - 0.65)))) + np.cos(7 * ratio)
        elif 0.8 <= ratio < 0.95:
            score = np.tanh(20 * (ratio - 0.85)) + 0.7
        else:
            score = 1 / (1 + np.exp(-30 * (ratio - 0.95)))
        penalty = 0
        for j in range(1, 7):
            mod_val = (item * j) % capacity
            frac = mod_val / (capacity * j)
            if frac < 0.05:
                penalty += frac * 3
            elif 0.05 <= frac < 0.2:
                penalty += frac * 1.2
            else:
                penalty += frac / (j + 2)
        extra_penalty = 0
        for k in range(1, 5):
            if ratio > 0.4 * k:
                extra_penalty += (np.exp(-k * ratio**2) + np.sin(ratio * np.pi * k)) * k
            else:
                extra_penalty += (np.log1p(k * ratio + 2) / (k + 1))**2
        complexity_factor = 0
        for m in range(1, 4):
            for n in range(m, 5):
                temp = (item * m * n) % (capacity + 1)
                ratio_temp = temp / (capacity * (m + n))
                if ratio_temp < 0.15:
                    complexity_factor += np.sqrt(ratio_temp * m * n)
                else:
                    complexity_factor -= np.log1p(ratio_temp * (m + n))
        if capacity % 3 == 0:
            priority = score + penalty * 1.2 + extra_penalty * 0.9 + complexity_factor * 0.5
        elif capacity % 2 == 0:
            priority = score + penalty + extra_penalty + complexity_factor * 0.3
        else:
            priority = score + penalty * 1.5 + extra_penalty * 0.8 + complexity_factor * 0.6
        if priority < 0:
            priority = 0
        priorities[i] = priority
    return priorities
